1	const PROCESSING_FEE = 5;
2	const COMPONENT_UNIT_PRICE = 25;
3	const COMPONENT_BLOCK_PRICE = 60;
4	const COMPONENT_BLOCK_SIZE = 3;
5	
6	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	};
12	
13	const INSURANCE_VALUE_BY_ITEM_TYPE: Record<string, number> = {
14	  sword: 1000,
15	  amulet: 600,
16	  staff: 800,
17	  potion: 400,
18	};
19	const COMPONENT_INSURANCE_VALUE = 250;
20	
21	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
22	
23	const FIRST_INSURANCE_RATE = 0.1;
24	const CURSE_SURCHARGE_RATE = 0.5;
25	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
26	const HIGH_ENCHANTMENT_THRESHOLD = 5;
27	const LOYALTY_DISCOUNT_RATE = 0.2;
28	const LOYALTY_YEARS_THRESHOLD = 2;
29	const FOLLOWUP_CONTRACT_DISCOUNT_RATE = 0.15;
30	
31	const CLAIM_DEDUCTIBLE = 100;
32	const CAP_MULTIPLIER = 2;
33	const HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD = 8;
34	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
35	
36	type Item = {
37	  type: string;
38	  material?: string;
39	  enchantment?: number;
40	  cursed?: boolean;
41	};
42	type Customer = { yearsWithMHPCO: number };
43	type QuoteStep = { op: "quote"; items: Item[] };
44	type Damage = { itemType: string; amount: number };
45	type Incident = { cause: string; damages: Damage[] };
46	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
47	type Step = QuoteStep | ClaimStep;
48	type Scenario = { customer: Customer; steps: Step[] };
49	type QuoteResult = { premium: number };
50	type ClaimResult = { payout: number; remainingCap: number };
51	type StepResult = QuoteResult | ClaimResult;
52	
53	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
54	
55	const isKnownItemType = (type: string): boolean =>
56	  type in BASE_PREMIUM_BY_ITEM_TYPE || COMPONENT_TYPES.has(type);
57	
58	const validateItems = (items: Item[]): void => {
59	  for (const item of items) {
60	    if (!isKnownItemType(item.type)) {
61	      throw new Error(`Unknown item type: ${item.type}`);
62	    }
63	  }
64	};
65	
66	const basePremiumForRegularItem = (item: Item): number =>
67	  BASE_PREMIUM_BY_ITEM_TYPE[item.type] ?? 0;
68	
69	const insuranceValueForItem = (item: Item): number =>
70	  isComponent(item)
71	    ? COMPONENT_INSURANCE_VALUE
72	    : INSURANCE_VALUE_BY_ITEM_TYPE[item.type] ?? 0;
73	
74	const itemSurcharges = (item: Item): number => {
75	  const base = basePremiumForRegularItem(item);
76	  let surcharge = 0;
77	  if (item.cursed) surcharge += base * CURSE_SURCHARGE_RATE;
78	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
79	    surcharge += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
80	  }
81	  return surcharge;
82	};
83	
84	const partition = <T,>(items: T[], predicate: (item: T) => boolean): [T[], T[]] =>
85	  items.reduce<[T[], T[]]>(
86	    ([yes, no], item) => (predicate(item) ? [[...yes, item], no] : [yes, [...no, item]]),
87	    [[], []],
88	  );
89	
90	const countByType = (items: Item[]): Record<string, number> =>
91	  items.reduce<Record<string, number>>((acc, item) => {
92	    acc[item.type] = (acc[item.type] ?? 0) + 1;
93	    return acc;
94	  }, {});
95	
96	const componentGroupPremium = (count: number): number =>
97	  count === COMPONENT_BLOCK_SIZE
98	    ? COMPONENT_BLOCK_PRICE
99	    : count * COMPONENT_UNIT_PRICE;
100	
101	const sumRegularItemBasePremiums = (items: Item[]): number =>
102	  items.reduce((total, item) => total + basePremiumForRegularItem(item), 0);
103	
104	const sumComponentPremiums = (components: Item[]): number =>
105	  Object.values(countByType(components)).reduce(
106	    (sum, count) => sum + componentGroupPremium(count),
107	    0,
108	  );
109	
110	const policyBasePremium = (items: Item[]): number => {
111	  const [components, regularItems] = partition(items, isComponent);
112	  return sumRegularItemBasePremiums(regularItems) + sumComponentPremiums(components);
113	};
114	
115	const sumItemSurcharges = (items: Item[]): number =>
116	  items.reduce((total, item) => total + itemSurcharges(item), 0);
117	
118	type QuoteContext = {
119	  customer: Customer;
120	  contractIndex: number;
121	};
122	
123	const policyModifierRate = (ctx: QuoteContext): number => {
124	  let rate = FIRST_INSURANCE_RATE;
125	  if (ctx.customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD) rate -= LOYALTY_DISCOUNT_RATE;
126	  if (ctx.contractIndex >= 1) rate -= FOLLOWUP_CONTRACT_DISCOUNT_RATE;
127	  return rate;
128	};
129	
130	const premiumForItems = (items: Item[], ctx: QuoteContext): number => {
131	  const policyBase = policyBasePremium(items);
132	  const surcharges = sumItemSurcharges(items);
133	  const policyModifiers = policyBase * policyModifierRate(ctx);
134	  return Math.ceil(policyBase + surcharges + policyModifiers + PROCESSING_FEE);
135	};
136	
137	type Policy = {
138	  items: Item[];
139	  remainingCap: number;
140	};
141	
142	const buildPolicy = (items: Item[]): Policy => ({
143	  items,
144	  remainingCap: items.reduce((sum, item) => sum + insuranceValueForItem(item), 0) * CAP_MULTIPLIER,
145	});
146	
147	const processQuote = (step: QuoteStep, ctx: QuoteContext): QuoteResult => {
148	  validateItems(step.items);
149	  return { premium: premiumForItems(step.items, ctx) };
150	};
151	
152	const isHighlyEnchanted = (item: Item): boolean =>
153	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD;
154	
155	const reimbursementForDamage = (item: Item, amount: number): number =>
156	  isHighlyEnchanted(item) ? amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE : amount;
157	
158	const payoutForDamage = (item: Item, amount: number): number => {
159	  const reimbursement = reimbursementForDamage(item, amount);
160	  return Math.max(0, reimbursement - CLAIM_DEDUCTIBLE);
161	};
162	
163	const findItemForDamage = (policy: Policy, damage: Damage): Item | undefined =>
164	  policy.items.find((item) => item.type === damage.itemType);
165	
166	const validateDamageCounts = (policy: Policy, damages: Damage[]): void => {
167	  const damageCounts: Record<string, number> = {};
168	  for (const damage of damages) {
169	    damageCounts[damage.itemType] = (damageCounts[damage.itemType] ?? 0) + 1;
170	  }
171	  const itemCounts = countByType(policy.items);
172	  for (const [type, count] of Object.entries(damageCounts)) {
173	    if (count > (itemCounts[type] ?? 0)) {
174	      throw new Error(`More damages of type ${type} than insured items`);
175	    }
176	  }
177	};
178	
179	const processClaim = (step: ClaimStep, policy: Policy): ClaimResult => {
180	  validateDamageCounts(policy, step.incident.damages);
181	  let totalPayout = 0;
182	  for (const damage of step.incident.damages) {
183	    if (damage.amount < 0) throw new Error(`Damage amount cannot be negative: ${damage.amount}`);
184	    const item = findItemForDamage(policy, damage);
185	    if (!item) throw new Error(`Damage references item not in policy: ${damage.itemType}`);
186	    const wanted = Math.floor(payoutForDamage(item, damage.amount));
187	    const actualPayout = Math.min(wanted, policy.remainingCap);
188	    totalPayout += actualPayout;
189	    policy.remainingCap -= actualPayout;
190	  }
191	  return { payout: totalPayout, remainingCap: policy.remainingCap };
192	};
193	
194	export const processScenario = (input: Scenario): { results: StepResult[] } => {
195	  let contractIndex = 0;
196	  const policies: Record<number, Policy> = {};
197	  const results: StepResult[] = input.steps.map((step, idx) => {
198	    if (step.op === "quote") {
199	      const ctx: QuoteContext = { customer: input.customer, contractIndex };
200	      contractIndex += 1;
201	      policies[idx] = buildPolicy(step.items);
202	      return processQuote(step, ctx);
203	    }
204	    return processClaim(step, policies[step.policy]);
205	  });
206	  return { results };
207	};
